import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Manage QR Codes","description":"","frontmatter":{"title":"Manage QR Codes","slug":"manage-your-qr-codes"},"headers":[],"relativePath":"marketer-hub/manage-your-qr-codes.md","filePath":"marketer-hub/manage-your-qr-codes.md"}'),n={name:"marketer-hub/manage-your-qr-codes.md"};function i(d,e,l,s,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>All QR Codes you create in the Branch Dashboard can be sorted and managed. Similar to Branch Short Links, it&#39;s important to keep your QR Codes organized to help you manage your campaigns.</p><h2 id="manage-qr-codes" tabindex="-1">Manage QR Codes <a class="header-anchor" href="#manage-qr-codes" aria-label="Permalink to &quot;Manage QR Codes&quot;">​</a></h2><p>In the Branch Dashboard, navigate to the QR Codes Manager <a href="https://dashboard.branch.io/qr-codes/manager" target="_blank" rel="noreferrer">page</a> where you can view all of the QR Codes created by you or the team.</p><p>You can sort your QR Codes by:</p><ul><li>Creation Date (will also indicate last edit date)</li><li>Creator</li><li>Title</li></ul><p>Additionally, you can click the suspension dots icon on any QR Code to perform a specific action:</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td>Edit</td><td>Allows you to edit the QR Code to customize things like analytics tags, redirects, link data, and QR Code looks.</td></tr><tr><td>Duplicate</td><td>Will navigate to the QR Code creation flow and copy any analytics tags, redirects, link data, and customization settings from the first QR Code.</td></tr><tr><td>QR Code</td><td>Brings up a model that allows you to download the QR Code as a PNG, JPEG, or SVG.</td></tr><tr><td>Analyze</td><td>Will navigate to the QR Codes Analytics page and apply the <em>Link Title</em> filter to only report on that specific QR Code.</td></tr><tr><td>Archive</td><td>Archives the QR Code. You can later filter for only &quot;archived&quot; QR Codes that allow your to <em>unarchive</em> the QR Code.</td></tr><tr><td>Delete</td><td>Deletes the QR Code.</td></tr></tbody></table>',9)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
